아래는 TypeScript로 구현된 제네릭 LRU 캐시 클래스입니다. 이 클래스는 `get`, `set`, `size` 메서드를 지원하며, 용량 초과 시 가장 오래 사용되지 않은 항목을 제거합니다. 또한 O(1)의 성능을 보장하는 구조로 설계되었습니다.

```typescript
/**
 * LRU 캐시 클래스를 정의합니다.
 * @template T 캐시할 데이터 타입입니다.
 */
class LRUCache<T> {
  private capacity: number;
  private cache: Map<string, T>;
  private order: string[];

  /**
   * 새로운 LRU 캐시 인스턴스를 생성합니다.
   * @param {number} capacity 캐시의 용량입니다.
   */
  constructor(capacity: number) {
    this.capacity = capacity;
    this.cache = new Map<string, T>();
    this.order = [];
  }

  /**
   * 주어진 키에 해당하는 값을 가져옵니다.
   * @param {string} key 검색할 키입니다.
   * @returns {T | undefined} 캐시된 값이 있으면 그 값을 반환하고, 없으면 undefined를 반환합니다.
   */
  get(key: string): T | undefined {
    if (!this.cache.has(key)) return undefined;

    // 사용 순서 업데이트
    this.order = this.order.filter(k => k !== key);
    this.order.push(key);

    return this.cache.get(key)!;
  }

  /**
   * 주어진 키와 값 쌍을 캐시에 설정합니다.
   * @param {string} key 설정할 키입니다.
   * @param {T} value 설정할 값입니다.
   */
  set(key: string, value: T): void {
    if (this.cache.has(key)) {
      // 사용 순서 업데이트
      this.order = this.order.filter(k => k !== key);
    } else if (this.cache.size >= this.capacity) {
      // 용량 초과 시 가장 오래된 항목 제거
      const oldestKey = this.order.shift()!;
      this.cache.delete(oldestKey);
    }

    this.cache.set(key, value);
    this.order.push(key);
  }

  /**
   * 현재 캐시에 저장된 항목의 수를 반환합니다.
   * @returns {number} 캐시의 현재 크기입니다.
   */
  size(): number {
    return this.cache.size;
  }
}

