React 19와 함께 TypeScript를 사용하여 `useDebounce` 커스텀 훅을 작성하려면, 주어진 함수가 지정된 딜레이 후에 호출되도록 하고, 메모리 누수를 방지하기 위해 적절한 클린업(logical cleanup)을 처리하는 것이 중요합니다. 이 훅은 `flush`와 `cancel` 메서드를 제공하여 딜레이된 함수 호출을 강제하거나 취소할 수 있도록 합니다.

다음은 `useDebounce` 커스텀 훅의 구현과 사용 예시입니다:

```tsx
import { useRef, useEffect, useCallback } from 'react';

// useDebounce hook definition
function useDebounce<T extends (...args: any[]) => void>(
  fn: T,
  delay: number = 300
) {
  const timeoutRef = useRef<NodeJS.Timeout | null>(null);

  // Debounced function with flush and cancel methods
  const debouncedFn = useCallback((...args: Parameters<T>) => {
    if (timeoutRef.current !== null) {
      clearTimeout(timeoutRef.current);
    }

    const handler = setTimeout(() => {
      fn(...args);
    }, delay);

    timeoutRef.current = handler as NodeJS.Timeout;

    // Return an object with flush and cancel methods
    return {
      flush: () => {
        if (timeoutRef.current !== null) {
          clearTimeout(timeoutRef.current);
          fn(...args);
        }
      },
      cancel: () => {
        if (timeoutRef.current !== null) {
          clearTimeout(timeoutRef.current);
          timeoutRef.current = null;
        }
      }
    };
  }, [fn, delay]);

  // Cleanup function to prevent memory leaks
  useEffect(() => {
    return () => {
      if (timeoutRef.current !== null) {
        clearTimeout(timeoutRef.current);
      }
    };
  }, []);

  return debouncedFn;
}

